SELECT AVG(logFC) AS average_logFC
FROM expression_data
WHERE FDR < 0.05;

SELECT COUNT(*) AS gene_count
FROM genes
WHERE gene_symbol = 'BRCA1';

SELECT sample_id, COUNT(expression_id) AS number_of_entries
FROM expression_data
GROUP BY sample_id;

SELECT MIN(start_position) AS min_start_position
FROM genes
WHERE chromosome = '1';
